import{_ as e,o as t,c as i,aA as o}from"./chunks/framework.CkLDEoW5.js";const u=JSON.parse('{"title":"AWESOME OCIM toolbox","description":"","frontmatter":{},"headers":[],"relativePath":"howtos/8_awesome_ocim.md","filePath":"howtos/8_awesome_ocim.md","lastUpdated":null}'),s={name:"howtos/8_awesome_ocim.md"};function n(r,a,d,l,h,p){return t(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="awesome-ocim" tabindex="-1">AWESOME OCIM toolbox <a class="header-anchor" href="#awesome-ocim" aria-label="Permalink to &quot;AWESOME OCIM toolbox {#awesome-ocim}&quot;">​</a></h1><p>The <a href="https://github.com/hengdiliang/AWESOME-OCIM" target="_blank" rel="noreferrer">AWESOME OCIM (AO)</a> is a MATLAB toolbox by John, Liang, Weber, DeVries, Primeau, Moore, Holzer, and Mahowald (2020) that bundles OCIM1 transport matrices alongside auxiliary GEOTRACES, WOA, and Weber-and-John datasets. AIBECS does not expose the AO contents directly, but it can fetch and unpack the toolbox locally so you can browse the underlying files yourself.</p><h2 id="Download-and-unpack" tabindex="-1">Download and unpack <a class="header-anchor" href="#Download-and-unpack" aria-label="Permalink to &quot;Download and unpack {#Download-and-unpack}&quot;">​</a></h2><p><code>AO.download_and_unpack()</code> registers a <code>DataDep</code>, downloads the upstream GitHub zip on first call, and returns the path of the unpacked tree:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AIBECS</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AO_path </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AO</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">download_and_unpack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>We hide the actual call from this rendered page so the docs build does not keep re-downloading from GitHub on every CI run.</p><h2 id="What-you-get" tabindex="-1">What you get <a class="header-anchor" href="#What-you-get" aria-label="Permalink to &quot;What you get {#What-you-get}&quot;">​</a></h2><p>Inside <code>AO_path</code> you will find:</p><ul><li><p><code>OCIM1/</code> — MATLAB-format transport matrices and grid info,</p></li><li><p><code>data/</code> — bundled observational fields (GEOTRACES, WOA, Weber–John),</p></li><li><p><code>util/</code> — MATLAB helper scripts.</p></li></ul><p>Refer to the AO citation in the docstring of <a href="/AIBECS.jl/v0.16.3/reference/functions#AIBECS.AO"><code>AO</code></a> when using any of the bundled data.</p><h2 id="Caveat:-GitHub-zip-distribution" tabindex="-1">Caveat: GitHub-zip distribution <a class="header-anchor" href="#Caveat:-GitHub-zip-distribution" aria-label="Permalink to &quot;Caveat: GitHub-zip distribution {#Caveat:-GitHub-zip-distribution}&quot;">​</a></h2><p>The AO is served as a GitHub archive zip rather than from a stable DOI mirror, so downloads depend on GitHub&#39;s availability and the upstream branch staying intact. If you plan to use the AO data heavily, copy the unpacked tree into your own storage. PRs to point this at a more durable mirror are welcome.</p><hr><p><em>This page was generated using <a href="https://github.com/fredrikekre/Literate.jl" target="_blank" rel="noreferrer">Literate.jl</a>.</em></p>`,14)])])}const b=e(s,[["render",n]]);export{u as __pageData,b as default};
